/**
 * Maps raw authentication errors into UI-friendly representations.
 * Extracts attempted remaining counts and provides translated messages.
 *
 * @param {unknown} error
 * @param {{ t: import("react-i18next").TFunction }} context
 */
export const mapLoginError = (error, { t }) => {
  const rawMessage = extractRawMessage(error) || t('loginFailed', { ns: 'auth' });
  const attemptsRemaining = parseAttempts(rawMessage);

  const translatedMessage = translateErrorMessage(rawMessage, attemptsRemaining, t);
  const suppressToast = attemptsRemaining !== null;

  return {
    rawMessage,
    translatedMessage,
    attemptsRemaining,
    suppressToast,
  };
};

const extractRawMessage = (error) => {
  if (!error) {return '';}

  if (typeof error === 'string') {return error;}

  const fromResponse =
    error?.response?.data?.message ??
    error?.response?.data?.error ??
    error?.response?.message ??
    error?.message;

  if (fromResponse) {return fromResponse;}

  return '';
};

const parseAttempts = (message) => {
  if (!message) {return null;}
  const attemptRegex = /(\d+)\s+(?:attempts?|tentatives?)\s+(?:remaining|left|restantes)/i;
  const match = message.match(attemptRegex);
  return match ? parseInt(match[1], 10) : null;
};

const translateErrorMessage = (rawMessage, attemptsRemaining, t) => {
  if (!rawMessage) {return '';}

  const lower = rawMessage.toLowerCase();
  const hasAttempts = attemptsRemaining !== null;

  // Connection refused errors
  if (lower.includes('econnrefused') || lower.includes('connection refused')) {
    return t('connectionRefused', { ns: 'auth', defaultValue: 'Unable to connect to our services. Please try again in a few moments.' });
  }

  if (lower.includes('invalid email') || lower.includes('invalid credentials')) {
    if (hasAttempts && attemptsRemaining <= 5) {
      return `${t('invalidCredentials', { ns: 'auth' })}. ${t('attemptsRemaining', {
        ns: 'auth',
        count: attemptsRemaining,
      })}`;
    }
    return `${t('invalidCredentials', { ns: 'auth' })}. ${t('tryAgain', { ns: 'auth' })}`;
  }

  // Check for iVerify invalid phone number
  if (lower.includes('customermsisdn') || lower.includes('invalid phone number for')) {
    return t('wrongPhoneNumber', { ns: 'auth', defaultValue: 'Wrong phone number' });
  }

  if (hasAttempts) {
    if (attemptsRemaining <= 5) {
      return t('attemptsRemaining', { ns: 'auth', count: attemptsRemaining });
    }
    return t('tryAgain', { ns: 'auth' });
  }

  if (lower.includes('account locked') || lower.includes('locked')) {
    return t('accountLocked', { ns: 'auth' });
  }

  // Network errors
  if (lower.includes('network error') || lower.includes('failed to fetch')) {
    return t('networkError', { ns: 'auth', defaultValue: 'Unable to connect to the server. Please check your internet connection and try again.' });
  }

  if (lower.includes('timeout') || lower.includes('timed out')) {
    return t('timeout', { ns: 'auth', defaultValue: 'The request took too long. Please try again.' });
  }

  return rawMessage;
};

