import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { LoginForm } from './LoginForm.jsx';
import { useLoginForm } from './hooks/useLoginForm.js';
import { LoadingSpinner } from '@/shared/components';
import i18n from '@/app/config/i18n/config/i18n.js';

import logoDark from '@/assets/images/logo-dark.png';
import logoLight from '@/assets/images/logo-light.png';

const computeLogoSrc = (effectiveTheme) =>
  effectiveTheme === 'dark' ? logoDark : logoLight;

const LoginPage = () => {
  const { t, ready } = useTranslation();
  const { theme, effectiveTheme, updateTheme } = useTheme();
  const [isI18nReady, setIsI18nReady] = useState(i18n.isInitialized);
  const {
    values,
    loading,
    errorState,
    showPassword,
    handleFieldChange,
    handleSubmit,
    togglePasswordVisibility,
    navigateToForgotPassword,
    navigateToCreateAccount,
  } = useLoginForm({ t });

  // Ensure i18n is ready and auth namespace is loaded before rendering
  useEffect(() => {
    let cleanup = null;

    const checkI18nReady = async () => {
      // Wait for i18n to be initialized
      if (i18n.isInitialized) {
        // Ensure auth namespace is loaded
        if (!i18n.hasResourceBundle(i18n.language, 'auth')) {
          await i18n.loadNamespaces('auth');
        }
        setIsI18nReady(true);
      } else {
        // Wait for initialization
        const handleInitialized = () => {
          i18n.loadNamespaces('auth').then(() => {
            setIsI18nReady(true);
          });
        };
        i18n.on('initialized', handleInitialized);

        cleanup = () => {
          i18n.off('initialized', handleInitialized);
        };
      }
    };

    checkI18nReady();

    return () => {
      if (cleanup) {cleanup();}
    };
  }, []);

  const logoSrc = computeLogoSrc(effectiveTheme);
  const handleThemeToggle = () => {
    if (theme?.toLowerCase() === 'light') {
      updateTheme('dark');
    } else if (theme?.toLowerCase() === 'dark') {
      updateTheme('auto');
    } else {
      updateTheme('light');
    }
  };

  // Wait for i18n to be ready before rendering the form
  // Check both ready (from useTranslation) and isI18nReady (from i18n instance)
  if (!ready && !isI18nReady) {
    return (
      <div className="login-container" style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        minHeight: '100vh',
        backgroundColor: effectiveTheme === 'dark' ? '#0a0a0a' : '#f5f5f5'
      }}>
        <LoadingSpinner size="large" />
      </div>
    );
  }

  return (
    <div className="login-container">
      <LoginForm
        t={t}
        values={values}
        loading={loading}
        errorState={errorState}
        showPassword={showPassword}
        onFieldChange={handleFieldChange}
        onSubmit={handleSubmit}
        onTogglePassword={togglePasswordVisibility}
        onForgotPassword={navigateToForgotPassword}
        onCreateAccount={navigateToCreateAccount}
        onThemeToggle={handleThemeToggle}
        theme={theme}
        effectiveTheme={effectiveTheme}
        logoSrc={logoSrc}
      />
    </div>
  );
};

export default LoginPage;

