import React, { useState, useEffect, useId } from 'react';
import { createPortal } from 'react-dom';
import { LanguageSelector, LoadingSpinner } from '@/shared/components';

const getErrorStyles = (attemptsRemaining) => {
  if (attemptsRemaining !== null && attemptsRemaining <= 2) {
    return {
      backgroundColor: 'var(--error-bg)',
      borderColor: 'var(--error)',
      color: 'var(--error)',
      border: '1px solid var(--error)',
      padding: '12px',
      borderRadius: '10px',
      marginBottom: '20px',
      textAlign: 'center',
      fontSize: '0.9rem',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '8px',
    };
  }

  return {
    color: 'var(--error)',
    background: 'var(--error-bg)',
    border: '1px solid var(--error)',
    padding: '12px',
    borderRadius: '10px',
    marginBottom: '20px',
    textAlign: 'center',
    fontSize: '0.9rem',
  };
};

export const LoginForm = ({
  t,
  values,
  loading,
  errorState,
  showPassword,
  onFieldChange,
  onSubmit,
  onTogglePassword,
  onForgotPassword,
  onCreateAccount,
  onThemeToggle,
  theme,
  effectiveTheme,
  logoSrc,
}) => {
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);

  // Generate unique IDs for form inputs for accessibility
  const emailId = useId();
  const passwordId = useId();

  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  const isMobile = windowWidth <= 480;
  const isTablet = windowWidth <= 768;
  const isSmallMobile = windowWidth <= 360;


  return (
    <form className="login-form" onSubmit={onSubmit} style={{
      position: 'relative',
      paddingTop: isSmallMobile ? '52px' : isMobile ? '56px' : isTablet ? '60px' : '48px'
    }}>


      <div style={{
        position: 'absolute',
        top: '20px',
        right: '20px',
        zIndex: 10,
      }}>
        <LanguageSelector />
      </div>
      <img
        src={logoSrc}
        alt="iSmartPay Logo"
        className="login-logo"
        style={{
          transition: 'opacity var(--transition-theme)',
          opacity: 1,
          maxWidth: isSmallMobile ? '100px' : isMobile ? '120px' : isTablet ? '160px' : '180px',
          marginTop: isSmallMobile ? '2px' : isMobile ? '4px' : isTablet ? '8px' : '0',
          marginBottom: isSmallMobile ? '16px' : isMobile ? '20px' : isTablet ? '24px' : '32px'
        }}
      />

      <h2 style={{ marginBottom: '24px', color: 'var(--text-primary)' }}>
        {t('signIn', { ns: 'auth' })}
      </h2>

      {errorState?.message && (
        <div
          role="alert"
          aria-live="assertive"
          aria-atomic="true"
          style={getErrorStyles(errorState.attemptsRemaining)}
        >
          {errorState.attemptsRemaining !== null && errorState.attemptsRemaining <= 2 && (
            <i
              className="fa-solid fa-triangle-exclamation"
              style={{ color: 'var(--error)', fontSize: '1rem' }}
              aria-hidden="true"
            ></i>
          )}
          {errorState.message}
        </div>
      )}

      <div className="input-wrapper" style={{ marginBottom: '16px' }}>
        <label htmlFor={emailId} className="sr-only">
          {t('enterEmail', { ns: 'auth' })}
        </label>
        <span className="input-icon" aria-hidden="true">
          <i className="fa-solid fa-envelope"></i>
        </span>
        <input
          type="email"
          id={emailId}
          placeholder={t('enterEmail', { ns: 'auth' })}
          value={values.email}
          onChange={(e) => onFieldChange('email', e.target.value)}
          disabled={loading}
          required
          autoComplete="email"
          aria-invalid={!!(errorState && !values.email)}
          aria-describedby={errorState ? `${emailId}-error` : undefined}
          style={{
            marginBottom: 0,
            borderColor: errorState && !values.email ? 'var(--error)' : undefined,
            color: 'var(--text-primary)',
          }}
        />
      </div>
      {errorState && !values.email && (
        <div id={`${emailId}-error`} className="sr-only" role="alert">
          {errorState.message}
        </div>
      )}

      <div className="input-wrapper" style={{ marginBottom: '16px', position: 'relative' }}>
        <label htmlFor={passwordId} className="sr-only">
          {t('enterPassword', { ns: 'auth' })}
        </label>
        <span className="input-icon" aria-hidden="true">
          <i className="fa-solid fa-key"></i>
        </span>
        <input
          type={showPassword ? 'text' : 'password'}
          id={passwordId}
          placeholder={t('enterPassword', { ns: 'auth' })}
          value={values.password}
          onChange={(e) => onFieldChange('password', e.target.value)}
          disabled={loading}
          required
          autoComplete="current-password"
          aria-invalid={!!(errorState && !values.password)}
          aria-describedby={errorState ? `${passwordId}-error` : undefined}
          style={{
            marginBottom: 0,
            paddingRight: '45px',
            borderColor: errorState && !values.password ? 'var(--error)' : undefined,
            color: 'var(--text-primary)',
          }}
        />
        <button
          type="button"
          onClick={onTogglePassword}
          style={{
            position: 'absolute',
            right: '16px',
            top: '50%',
            transform: 'translateY(-50%)',
            background: 'none',
            border: 'none',
            color: 'var(--text-muted)',
            cursor: 'pointer',
            padding: '0',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            width: '20px',
            height: '20px',
          }}
          aria-label={
            showPassword
              ? t('hidePassword', { ns: 'auth' })
              : t('showPassword', { ns: 'auth' })
          }
        >
          <i className={`fa-solid ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`} aria-hidden="true"></i>
        </button>
      </div>
      {errorState && !values.password && (
        <div id={`${passwordId}-error`} className="sr-only" role="alert">
          {errorState.message}
        </div>
      )}

      <div className="forgot-password-link">
        <a onClick={onForgotPassword} style={{ cursor: 'pointer', color: 'var(--accent)' }}>
          {t('forgotPassword', { ns: 'auth' })}
        </a>
      </div>

      <button
        type="submit"
        disabled={loading}
        style={{
          width: '100%',
          marginBottom: '20px',
          opacity: loading ? 0.7 : 1,
          cursor: loading ? 'not-allowed' : 'pointer',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: '8px',
          backgroundColor: '#004895',
        }}
      >
        {loading ? t('loggingIn', { ns: 'auth' }) : t('signInButton', { ns: 'auth' })}
      </button>

      {loading && createPortal(
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            width: '100vw',
            height: '100vh',
            backgroundColor: effectiveTheme === 'dark'
              ? 'rgba(0, 0, 0, 0.85)'
              : 'rgba(0, 0, 0, 0.5)',
            backdropFilter: 'blur(4px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 99999,
            margin: 0,
            padding: 0,
          }}
        >
          <div
            style={{
              backgroundColor: effectiveTheme === 'dark'
                ? '#141414'
                : 'var(--card)',
              borderRadius: '16px',
              padding: '48px',
              boxShadow: 'var(--shadow-xl)',
              border: '1px solid var(--border-primary)',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              minWidth: '120px',
              minHeight: '120px',
            }}
          >
            <LoadingSpinner size="large" />
          </div>
        </div>,
        document.body
      )}

      <hr style={{ marginBottom: '16px' }} />
      <p style={{ textAlign: 'center', marginBottom: '10px' }}>
        {t('dontHaveAccount', { ns: 'auth' })}
      </p>

      <button
        type="button"
        onClick={onCreateAccount}
        style={{ width: '100%', backgroundColor: '#23bd00' }}
      >
        {t('createNewAccount', { ns: 'auth' })}
      </button>
    </form>
  );
};

