import { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useLanguage } from '@/app/providers/LanguageContext.jsx';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { usePermissions } from '@/app/providers/PermissionsContext.jsx';
import { authService, tokenService } from '@/features/auth/services';
import { profileService } from '@/features/settings/services';
import { securityService } from '@/features/settings/services';
import { mapLoginError } from '@/shared/utils/errors/authErrorMapper.js';
import { validateLoginValues } from '@/shared/utils/validation/authSchemas.js';
import logger from '@/shared/utils/logger.js';


/**
 * Encapsulates login form state, validation, and submission side-effects.
 *
 * @param {{ t: import("react-i18next").TFunction }} params
 */
export const useLoginForm = ({ t }) => {
  const navigate = useNavigate();
  const { success, error: showError } = useToast();
  const { changeLanguage } = useLanguage();
  const { updateTheme } = useTheme();
  const { loadPermissions, isInitialized } = usePermissions();

  const [values, setValues] = useState({ email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [errorState, setErrorState] = useState(null);

  useEffect(() => {
    if (tokenService.isAuthenticated()) {
      navigate('/dashboard');
    }
  }, [navigate]);

  const resetForm = useCallback(() => {
    setValues({ email: '', password: '' });
    setShowPassword(false);
  }, []);

  const handleFieldChange = useCallback((field, value) => {
    setValues((prev) => ({
      ...prev,
      [field]: value,
    }));
    setErrorState(null);
  }, []);

  const togglePasswordVisibility = useCallback(() => {
    setShowPassword((prev) => !prev);
  }, []);

  const navigateToForgotPassword = useCallback(() => {
    navigate('/forgot-password');
  }, [navigate]);

  const navigateToCreateAccount = useCallback(() => {
    navigate('/user-type-selection');
  }, [navigate]);

  const handleSuccessfulLogin = useCallback(
    async (data, email) => {
      const responseData = data.data;

      // Check if 2FA is required first
      if (responseData.require2FA) {
        logger.debug('2FA required, redirecting to 2FA page');
        success(t('pleaseEnterAuthenticationCode', { ns: 'auth' }));
        setTimeout(() => {
          navigate('/two-factor-auth', {
            state: {
              userId: responseData.userId,
              email,
            },
          });
        }, 1000);
        return false;
      }

      // If 2FA is not required, proceed with normal login flow
      const user = responseData.user;
      const tokens = responseData.tokens;

      // First, store the tokens temporarily to check 2FA status
      tokenService.setAuthData({
        token: tokens.accessToken,
        refreshToken: tokens.refreshToken,
        user: {
          ...user,
          userType: user.userType || user.user_type || user.usertype || 'individual',
          user_type: user.userType || user.user_type || user.usertype || 'individual',
          usertype: user.userType || user.user_type || user.usertype || 'individual',
        },
      });

      // Check if 2FA is enabled for this user
      try {
        const securityData = await securityService.getAccountSecurity();
        const is2FAEnabled = securityData?.data?.twoFaEnabled ||
          securityData?.data?.is2FAEnabled ||
          securityData?.twoFaEnabled ||
          false;

        logger.debug('2FA status check', { is2FAEnabled, securityData: securityData?.data });

        if (is2FAEnabled) {
          // Clear the temporarily stored tokens since 2FA is required
          tokenService.clearAuthData();

          success(t('pleaseEnterAuthenticationCode', { ns: 'auth' }));
          setTimeout(() => {
            navigate('/two-factor-auth', {
              state: {
                userId: user.id,
                email,
              },
            });
          }, 1000);
          return false;
        }
      } catch (error) {
        logger.warn('Could not check 2FA status, proceeding with normal login', { error });
        // If we can't check 2FA status, proceed with normal login
      }

      // If 2FA is not enabled or check failed, proceed with normal login flow
      const userTypeValue = user.userType || user.user_type || user.usertype || 'individual';

      // Update the stored user data with the correct user type
      tokenService.setAuthData({
        token: tokens.accessToken,
        refreshToken: tokens.refreshToken,
        user: {
          ...user,
          userType: userTypeValue,
          user_type: userTypeValue,
          usertype: userTypeValue,
        },
      });

      tokenService.setUserType(userTypeValue);

      // Load preferences and profile before navigating
      try {
        const [profileResult, prefsResult] = await Promise.allSettled([
          profileService.getUserProfile(),
          profileService.getUserPreferences(),
        ]);

        const profile =
          profileResult.status === 'fulfilled'
            ? profileResult.value?.data ?? profileResult.value ?? {}
            : {};
        const prefs =
          prefsResult.status === 'fulfilled'
            ? prefsResult.value?.data ?? prefsResult.value ?? {}
            : {};

        const existingUserData = JSON.parse(localStorage.getItem('userData') || '{}');
        // Always use the fresh login user ID from the login response (data.user.id)
        // This ensures we use the correct ID from the server, not a stale one from localStorage
        const loginUserId = user.id || existingUserData.id;
        const merged = {
          ...existingUserData,
          ...user, // Preserve user data from login response (including businesses array)
          ...profile,
          id: loginUserId,
          preferences: {
            currency: prefs.currency || existingUserData.preferences?.currency || 'GHS',
            language: prefs.language || existingUserData.preferences?.language || 'en',
            notification_preference:
              prefs.notification_preference || prefs.notificationPreference || existingUserData.preferences?.notification_preference || 'email',
            theme: prefs.theme || existingUserData.preferences?.theme || 'light',
            timezone: prefs.timezone || existingUserData.preferences?.timezone || 'Africa/Accra',
          },
          updated_at: new Date().toISOString(),
        };
        localStorage.setItem('userData', JSON.stringify(merged));

        // Apply language and theme from preferences before navigating
        if (merged.preferences.language) {
          await changeLanguage(merged.preferences.language);
        }
        if (merged.preferences.theme) {
          updateTheme(merged.preferences.theme);
        }
      } catch (error) {
        logger.error('Error loading preferences', { error });
        // Continue with navigation even if preferences fail
      }

      if (data.verificationLevel !== undefined) {
        tokenService.setVerificationLevel(data.verificationLevel);
      } else if (user.verificationLevel !== undefined) {
        tokenService.setVerificationLevel(user.verificationLevel);
      }

      if (user.wallet_balance !== undefined) {
        tokenService.setWalletBalance(user.wallet_balance);
      }

      if (user.usertype) {
        tokenService.setUserType(user.usertype);
      }

      success(t('loginSuccessfulExclamation', { ns: 'auth' }));
      resetForm();

      // Load permissions and wait for them to be initialized before navigating
      // This ensures team members see the correct pages immediately (no visible change)
      try {
        // Await permissions load - this will complete when permissions are initialized
        await loadPermissions();
        logger.debug('Permissions loaded, navigating to dashboard');
        navigate('/dashboard');
      } catch (error) {
        logger.error('Error loading permissions', { error });
        // Continue with navigation even if permissions fail
        navigate('/dashboard');
      }

      // Navigate to dashboard after permissions are loaded
      navigate('/dashboard');

      return true;
    },
    [navigate, resetForm, success, t, changeLanguage, updateTheme, loadPermissions]
  );

  // No frontend rate limiting - handled by backend only
  const handleSubmit = useCallback(async (event) => {
    event.preventDefault();
    setErrorState(null);

    // Clear any stuck logout flag to allow login attempts
    if (typeof localStorage !== 'undefined') {
      localStorage.removeItem('isLoggingOut');
    }

    const validation = validateLoginValues(t, values);
    if (!validation.success) {
      const message = validation.message;
      setErrorState({ message, attemptsRemaining: null });
      showError(message);
      return;
    }

    setLoading(true);

    try {
      const data = await authService.login(values.email, values.password);
      const shouldExit = await handleSuccessfulLogin(data, values.email);
      if (shouldExit === false) {
        return;
      }
    } catch (err) {
      const mapped = mapLoginError(err, { t });
      setErrorState({
        message: mapped.translatedMessage,
        attemptsRemaining: mapped.attemptsRemaining,
      });
      if (!mapped.suppressToast) {
        showError(mapped.translatedMessage);
      }
    } finally {
      setLoading(false);
    }
  }, [values, t, showError, handleSuccessfulLogin]);

  return useMemo(
    () => ({
      values,
      loading,
      errorState,
      showPassword,
      handleFieldChange,
      handleSubmit,
      togglePasswordVisibility,
      navigateToForgotPassword,
      navigateToCreateAccount,
    }),
    [
      errorState,
      handleFieldChange,
      handleSubmit,
      loading,
      navigateToCreateAccount,
      navigateToForgotPassword,
      showPassword,
      togglePasswordVisibility,
      values,
    ]
  );
};

